// Parse Claude's response
const response = $json;
let content = '';

// Extract content from Claude's response structure
if (response.content && Array.isArray(response.content)) {
  content = response.content
    .filter(item => item.type === 'text')
    .map(item => item.text)
    .join('\n');
} else if (typeof response === 'string') {
  content = response;
} else {
  throw new Error('Unexpected response format from Claude API');
}

// Extract code blocks and file structures
const files = [];
const codeBlockRegex = /```(?:jsx?|tsx?|json|js|ts|javascript|typescript)?\n([\s\S]*?)```/g;
const fileIndicators = [
  /\/\/ File: (.+?)\n/,
  /\/\/ file: (.+?)\n/,
  /\/\/ (.+?\.(jsx?|tsx?|json|css|md))\n/,
  /\/\* File: (.+?) \*\//,
  /# File: (.+?)\n/,
  /<!-- File: (.+?) -->/
];

let match;
let lastIndex = 0;

// First, try to extract files from code blocks
while ((match = codeBlockRegex.exec(content)) !== null) {
  const codeContent = match[1];
  let fileName = null;
  let cleanContent = codeContent;

  // Try to find filename in the code block
  for (const regex of fileIndicators) {
    const fileMatch = codeContent.match(regex);
    if (fileMatch) {
      fileName = fileMatch[1].trim();
      cleanContent = codeContent.replace(regex, '').trim();
      break;
    }
  }

  // If no filename found, try to find it before the code block
  if (!fileName) {
    const beforeBlock = content.substring(lastIndex, match.index);
    const lines = beforeBlock.split('\n');
    for (let i = lines.length - 1; i >= 0 && i >= lines.length - 5; i--) {
      const line = lines[i].trim();
      if (line.includes('.js') || line.includes('.jsx') || 
          line.includes('.ts') || line.includes('.tsx') || 
          line.includes('.json') || line.includes('.md')) {
        fileName = line.replace(/[*`#<>:\-]/g, '').trim();
        break;
      }
    }
  }

  if (fileName && cleanContent) {
    files.push({
      fileName: fileName,
      content: cleanContent
    });
  }

  lastIndex = match.index + match[0].length;
}

// If no files extracted, create a default App.js
if (files.length === 0) {
  console.warn('No code files found in Claude response');
  files.push({
    fileName: 'App.js',
    content: content
  });
}

return {
  parsedFiles: files,
  fileCount: files.length,
  rawResponse: content,
  timestamp: new Date().toISOString()
};

